#include <stdio.h>
#include <assert.h>

int
main()
{
    int n, x=0, y=0;
    scanf("%d%*c", &n);
    for (int i = 0; i < n; ++i) {
        char c;
        scanf("%c", &c);
        if (c == 'U') {
            y += 1;
        }
        else if (c == 'D') {
            y -= 1;
        }
        else if (c == 'R') {
            x += 1;
        }
        else if (c == 'L') {
            x -= 1;
        }
        else {
            assert(0);
        }
    }
    if (x < 0) x = -x;
    if (y < 0) y = -y;
    printf("%d\n", n - x - y);
    return 0;
}

